(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[1112],{3099:(n,s,a)=>{"use strict";a.r(s),a.d(s,{data:()=>e});const e={key:"v-10190945",path:"/python/data-type/list/",title:"Lists",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"ความแตกต่างระหว่าง List และ Tuple",slug:"ความแตกต่างระหว่าง-list-และ-tuple",children:[{level:3,title:"สร้าง List ขึ้นมาใหม่",slug:"สร้าง-list-ขึ้นมาใหม่",children:[]}]},{level:2,title:"เข้าถึงข้อมูลใน List",slug:"เข้าถึงข้อมูลใน-list",children:[]},{level:2,title:"การนับลำดับของ List",slug:"การนับลําดับของ-list",children:[]},{level:2,title:"เพื่มข้อมูลไปใน List",slug:"เพื่มข้อมูลไปใน-list",children:[{level:3,title:"ด้วยการใช้ method .append()",slug:"ด้วยการใช้-method-append",children:[]},{level:3,title:"โดยการบวกจาก List อื่น",slug:"โดยการบวกจาก-list-อื่น",children:[]}]},{level:2,title:"การแปลงระหว่าง String และ List",slug:"การแปลงระหว่าง-string-และ-list",children:[{level:3,title:"แปลง String -> List ด้วย .split()",slug:"แปลง-string-list-ด้วย-split",children:[]},{level:3,title:"แปลง List -> String ด้วย .join()",slug:"แปลง-list-string-ด้วย-join",children:[]}]},{level:2,title:"การเรียงข้อมูลใหม่ใน List",slug:"การเรียงข้อมูลใหม่ใน-list",children:[{level:3,title:"ใช้ method .sort()",slug:"ใช้-method-sort",children:[]},{level:3,title:"ใช้ function sorted()",slug:"ใช้-function-sorted",children:[]},{level:3,title:"ข้อสังเกตของการใช้ sort",slug:"ข้อสังเกตของการใช้-sort",children:[]},{level:3,title:"การทำการ sort แบบมี filter",slug:"การทําการ-sort-แบบมี-filter",children:[]}]},{level:2,title:"หาข้อมูลใน List",slug:"หาข้อมูลใน-list",children:[{level:3,title:"หาว่าข้อมูลอยู่ที่ลำดับใดด้วย .index()",slug:"หาว่าข้อมูลอยู่ที่ลําดับใดด้วย-index",children:[]},{level:3,title:"นำข้อมูลออกไปและไปแทนในตัวแปรด้วย .pop()",slug:"นําข้อมูลออกไปและไปแทนในตัวแปรด้วย-pop",children:[]},{level:3,title:"นำข้อมูลออกจาก List ด้วย .remove()",slug:"นําข้อมูลออกจาก-list-ด้วย-remove",children:[]},{level:3,title:"แทนค่าใน List ด้วย .replace()",slug:"แทนค่าใน-list-ด้วย-replace",children:[]}]}],filePathRelative:"python/data-type/list/README.md",git:{updatedTime:162676698e4,contributors:[]}}},1884:(n,s,a)=>{"use strict";a.r(s),a.d(s,{default:()=>t});const e=(0,a(6252).uE)('<h1 id="lists" tabindex="-1"><a class="header-anchor" href="#lists" aria-hidden="true">#</a> Lists</h1><p>ลิสต์ (หรือที่ในภาษาคอมพิวเตอร์อื่นๆเรียกว่า array) โดยมันมีหน้าที่เก็บข้อมูลที่เป็นกลุ่ม ซึ่งแตกต่างกันกับการเก็บตัวแปรทั่วไปเพราะว่าเก็บข้อมูลได้เยอะมากๆ และเรียงลำดับได้ด้วย</p><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>ใน Python นั้น จะถือ List ว่ามีค่าไม่เท่ากับ Array ดังนั้นอย่าเรียกว่ามันคืออันเดียวกันนะครับ</p></div><p>โดยปกติแล้ว น้องจะเก็บข้อมูลโดยการใช้แบบนี้ครับ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>my_var1 <span class="token operator">=</span> <span class="token number">12</span>\nmy_var2 <span class="token operator">=</span> <span class="token number">24</span>\nmy_var3 <span class="token operator">=</span> <span class="token number">36</span>\nmy_var4 <span class="token operator">=</span> <span class="token number">48</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>แต่หากว่าน้องเอามาใส่ list ก็จะได้แบบนี้ครับ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>my_var <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">12</span><span class="token punctuation">,</span> <span class="token number">24</span><span class="token punctuation">,</span> <span class="token number">36</span><span class="token punctuation">,</span> <span class="token number">48</span><span class="token punctuation">]</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>ทำให้เวลาเราต้องการเรียกค่า ก็เรียกจากตัวแปรเดียว และเข้าไปใน list แทนครับ</p><h2 id="ความแตกต่างระหว่าง-list-และ-tuple" tabindex="-1"><a class="header-anchor" href="#ความแตกต่างระหว่าง-list-และ-tuple" aria-hidden="true">#</a> ความแตกต่างระหว่าง List และ Tuple</h2><p>หากเปรียบเทียบกันด้านการใช้งานตัวข้อมูล ก็จะไม่แตกต่างกัน แต่ถ้าน้องๆมาดูจริงๆแล้ว ตัว Tuple จะแตกต่างจาก List ในด้านของการเอาข้อมูลเข้าไปนั่นเอง ซึ่งตัว Tuple ไม่สามารถเอาข้อมูลเข้าไปได้ เช่นเดียวกันกับการลบข้อมูลออก</p><p>ถ้าจะให้อธิบายง่ายๆ ก็คือ</p><ul><li>Tuple เป็นเหมือน Read ได้อย่างเดียว</li><li>List สามารถที่จะทำการ Read และ Write ได้ด้วย</li></ul><p>น้องๆก็ควรเลือกประเภท Array ตามแต่ละสถานการณ์แล้วกันนะครับ อิอิ</p><h3 id="สร้าง-list-ขึ้นมาใหม่" tabindex="-1"><a class="header-anchor" href="#สร้าง-list-ขึ้นมาใหม่" aria-hidden="true">#</a> สร้าง List ขึ้นมาใหม่</h3><p>ในภาษา Python น้องๆไม่จำเป็นที่จะต้องประกาศตัวแปรการจัดเก็บนะครับสามารถบอกค่าให้มันได้เลย</p><p>หากน้องๆอยากที่จะสร้าง List เปล่าขึ้นมา 1 อัน ก็สามารถเขียนได้ว่า</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var1 <span class="token operator">=</span> <span class="token builtin">list</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>หรือ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var2 <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>แต่ถ้าน้องต้องการระบุขนาดไว้ล่วงหน้า ก็สามารถใส่ค่าว่างเข้าไปได้ครับ ดังนี้</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var3 <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token boolean">None</span><span class="token punctuation">,</span> <span class="token boolean">None</span><span class="token punctuation">,</span> <span class="token boolean">None</span><span class="token punctuation">]</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>หรือถ้าน้องต้องการใส่ข้อมูลเข้าไปเองเลย ก็สามารถทำได้ดังนี้ครับ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>kumamon <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&#39;Kumamon&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;is&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;so&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;cute&#39;</span><span class="token punctuation">]</span>\nnumbers <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">]</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="เข้าถึงข้อมูลใน-list" tabindex="-1"><a class="header-anchor" href="#เข้าถึงข้อมูลใน-list" aria-hidden="true">#</a> เข้าถึงข้อมูลใน List</h2><p>น้องๆสามารถเข้าถึงข้อมูลได้โดยการใช้ [] เหมือน String เลย</p><p>ตัวอย่างเช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>kumamon <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&#39;Kumamon&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;is&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;so&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;cute&#39;</span><span class="token punctuation">]</span>\nvar1 <span class="token operator">=</span> kumamon<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span>\n\n<span class="token keyword">print</span><span class="token punctuation">(</span>var1<span class="token punctuation">)</span> <span class="token comment"># ก็จะได้ผลลัพท์เป็น &#39;Kumamon&#39;</span>\n<span class="token builtin">type</span><span class="token punctuation">(</span>var1<span class="token punctuation">)</span> <span class="token comment"># ก็จะเป็นประเภท String</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>หรืออาจจะเลือกหลายๆอันเหมือน String เช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>kumamon <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&#39;Kumamon&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;is&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;so&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;cute&#39;</span><span class="token punctuation">]</span>\nvar1 <span class="token operator">=</span> kumamon<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">:</span><span class="token number">2</span><span class="token punctuation">]</span>\n\n<span class="token keyword">print</span><span class="token punctuation">(</span>var1<span class="token punctuation">)</span> <span class="token comment"># ก็จะได้ผลลัพท์เป็น [&#39;Kumamon&#39;, &#39;is&#39;, &#39;so&#39;]</span>\n<span class="token builtin">type</span><span class="token punctuation">(</span>var1<span class="token punctuation">)</span> <span class="token comment"># ก็จะออกมาเป็น &lt;class &#39;list&#39;&gt; (ตัวแปรประเภท list)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="การนับลําดับของ-list" tabindex="-1"><a class="header-anchor" href="#การนับลําดับของ-list" aria-hidden="true">#</a> การนับลำดับของ List</h2><p>หลักการของการนับลำดับข้อมูลใน List ก็เหมือนกับ String นะครับ โดยให้ตัวแรกมีค่าเท่ากับ 0 และนับไปเรื่อยๆครับ</p><p>ตัวอย่างการนับและจัดเก็บครับ</p><table><thead><tr><th><strong>Value</strong></th><th>Kumamon</th><th>is</th><th>so</th><th>cute</th></tr></thead><tbody><tr><td><strong>Array Number</strong></td><td>0</td><td>1</td><td>2</td><td>3</td></tr><tr><td><strong>Logical Number</strong></td><td>1</td><td>2</td><td>3</td><td>4</td></tr></tbody></table><h2 id="เพื่มข้อมูลไปใน-list" tabindex="-1"><a class="header-anchor" href="#เพื่มข้อมูลไปใน-list" aria-hidden="true">#</a> เพื่มข้อมูลไปใน List</h2><h3 id="ด้วยการใช้-method-append" tabindex="-1"><a class="header-anchor" href="#ด้วยการใช้-method-append" aria-hidden="true">#</a> ด้วยการใช้ method <code>.append()</code></h3><p>การใช้ method นี้ืทำให้ข้อมูลที่น้องใส่เข้าไปใน Parameter ไปอยู่ในลำดับสุดท้ายของ list ทันที</p><div class="language-Python ext-Python line-numbers-mode"><pre class="language-Python"><code>kumamon = [1,2,3,4]\nkumamon.append(5)\n\n# kumamon now equals to\n[1, 2, 3, 4, 5]\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>น้องๆจะเห็นว่าข้อมูลที่ถูก append (ก็คือเลข 5) จะไปอยู่ลำดับสุดท้าย</p><h3 id="โดยการบวกจาก-list-อื่น" tabindex="-1"><a class="header-anchor" href="#โดยการบวกจาก-list-อื่น" aria-hidden="true">#</a> โดยการบวกจาก List อื่น</h3><p>น้องๆก็สามารถใช้การ concat ตัว list ได้เหมือนกัน</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>text1 <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;Happy&quot;</span><span class="token punctuation">]</span>\ntext2 <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;Kumamon&quot;</span><span class="token punctuation">]</span>\ntext1 <span class="token operator">+=</span> text2\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>ทำให้ตัวแปร text1 มีค่าเท่ากับ <code>[&quot;Happy&quot;, &quot;Kumamon&quot;]</code></p><h2 id="การแปลงระหว่าง-string-และ-list" tabindex="-1"><a class="header-anchor" href="#การแปลงระหว่าง-string-และ-list" aria-hidden="true">#</a> การแปลงระหว่าง String และ List</h2><h3 id="แปลง-string-list-ด้วย-split" tabindex="-1"><a class="header-anchor" href="#แปลง-string-list-ด้วย-split" aria-hidden="true">#</a> แปลง String -&gt; List ด้วย <code>.split()</code></h3><p>โดยน้องๆจะใส่เป็นตัวที่ใช้แยก string ออกมาเป็น list เข้าไปที่ตัว parameter</p><p>ตัวอย่างการใช้งาน</p><div class="language-Python ext-Python line-numbers-mode"><pre class="language-Python"><code>text = &quot;I am a happy Kumamon&quot;\ntext = text.split() \n# ตัวแปร text มีค่าเป็น [&#39;I&#39;, &#39;am&#39;, &#39;a&#39;, &#39;happy&#39;, &#39;Kumamon&#39;]\n\ntext = &quot;I,am,a,happy,Kumamon&quot;\ntext = text.split(&quot;,&quot;) \n# ตัวแปร text มีค่าเป็น [&#39;I&#39;, &#39;am&#39;, &#39;a&#39;, &#39;happy&#39;, &#39;Kumamon&#39;]\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>จะเห็นได้่ว่า ในตัวอย่างที่ 2 พี่ได้ใช้ <code>.split(&#39;,&#39;)</code> ทำให้เมื่อตัว Python เจอตัวอักษร <code>,</code> ก็จะทำการ split ครับ</p><p>แต่หากว่าไม่ใส่อะไรเลย (เหมือนในตัวอย่างที่ 1) ก็จะเห็นว่ามันจะใช้ space เพื่อการ split ครับ</p><h3 id="แปลง-list-string-ด้วย-join" tabindex="-1"><a class="header-anchor" href="#แปลง-list-string-ด้วย-join" aria-hidden="true">#</a> แปลง List -&gt; String ด้วย <code>.join()</code></h3><p>โดยก็จะใช้หลักการคล้ายๆกัน แต่คราวนี้จะเปลี่ยน List ให้เป็น String<br> น้องๆสามารถใส่ ตัวอักษร หรือคำหน้า method เพื่อให้มันแยกออกมาแบบต่างๆ (เหมือนคราว split) หรือไม่ก็ได้</p><p>ตัวอย่างการใช้งาน</p><div class="language-Python ext-Python line-numbers-mode"><pre class="language-Python"><code>text = [&#39;I&#39;, &#39;am&#39;, &#39;a&#39;, &#39;happy&#39;, &#39;Kumamon&#39;]\nprint(&quot; &quot;.join(text)) # ก็จะปรี้นท์ออกมาเป็น &quot;I am a happy Kumamon&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="การเรียงข้อมูลใหม่ใน-list" tabindex="-1"><a class="header-anchor" href="#การเรียงข้อมูลใหม่ใน-list" aria-hidden="true">#</a> การเรียงข้อมูลใหม่ใน List</h2><h3 id="ใช้-method-sort" tabindex="-1"><a class="header-anchor" href="#ใช้-method-sort" aria-hidden="true">#</a> ใช้ method <code>.sort()</code></h3><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">]</span>\nmy_list<span class="token punctuation">.</span>sort<span class="token punctuation">(</span><span class="token punctuation">)</span>\n\n<span class="token comment"># my_list now equals to</span>\n<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">]</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="ใช้-function-sorted" tabindex="-1"><a class="header-anchor" href="#ใช้-function-sorted" aria-hidden="true">#</a> ใช้ function <code>sorted()</code></h3><p>วิธีเหมือนกับ <code>.sort()</code> เลย แต่ว่าอันนี้เป็น built-in function เท่านั้นเอง</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">]</span>\n<span class="token builtin">sorted</span><span class="token punctuation">(</span>my_list<span class="token punctuation">)</span>\n\n<span class="token comment"># my_list now equals to</span>\n<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">]</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>แต่หากว่าน้องๆต้องการที่จะ sort จากหลังมาหน้า<br> ก็ให้ใส่ Parameter <code>reverse</code> และให้มันเป็น True ครับ</p><p>ตัวอย่างเช่น</p><div class="language-Python ext-Python line-numbers-mode"><pre class="language-Python"><code>my_list = [1, 3, 4, 2, 5]\nmy_list.sort(reverse = True)\n\n# my_list now equals to\n[5, 4, 3, 2, 1]\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>เช่นเดียวกันกับการใช้ <code>sorted()</code></p><h3 id="ข้อสังเกตของการใช้-sort" tabindex="-1"><a class="header-anchor" href="#ข้อสังเกตของการใช้-sort" aria-hidden="true">#</a> ข้อสังเกตของการใช้ sort</h3><p>การ sort นี้จะทำการเลือกจากตัวข้อมูลที่มีค่า ASCII ต่ำที่สุดก่อน ทำให้การ sort ตัวอักษรเป็นแบบนี้</p><div class="language-Python ext-Python line-numbers-mode"><pre class="language-Python"><code>my_list = [&#39;a&#39;, &#39;A&#39;, &#39;z&#39;, &#39;Z&#39;]\nmy_list.sort() # หรือใช้ sorted(my_list)\n\n# my_list ตอนนี้ก็จะมีค่าเท่ากับ [&#39;A&#39;, &#39;Z&#39;, &#39;a&#39;, &#39;z&#39;]\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>และด้วยข้อจำกัด ทำให้น้องๆทำการ sort ข้อมูลที่เป็นประเภทต่างกันไม่ได้</p><div class="language-Python ext-Python line-numbers-mode"><pre class="language-Python"><code>my_list = [9, 1, &#39;a&#39;, &#39;A&#39;]\nmy_list.sort()\n\n# ก็จะเกิด ValueError เพราะไม่สามารถเทียบค่าระหว่างประเภทได้\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="การทําการ-sort-แบบมี-filter" tabindex="-1"><a class="header-anchor" href="#การทําการ-sort-แบบมี-filter" aria-hidden="true">#</a> การทำการ sort แบบมี filter</h3><p>บางครั้ง น้องต้องการที่จะ sort แบบพิเศษ ไม่อยาก sort แบบที่มันมีให้มาแล้ว<br> ดังนั้นน้องจึงต้องใส่ parameter <code>key</code> เข้าไปด้วยครับ</p><p>ตัวอย่างการใช้งาน</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&#39;My&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;name&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;is&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;Kumamon&#39;</span><span class="token punctuation">]</span>\nmy_list<span class="token punctuation">.</span>sort<span class="token punctuation">(</span>key <span class="token operator">=</span> <span class="token builtin">str</span><span class="token punctuation">.</span>lower<span class="token punctuation">)</span>\n\n<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>ก็จะได้ออกมาเป็น [&#39;is&#39;, &#39;Kumamon&#39;, &#39;My&#39;, &#39;name&#39;] เนื่องจากบอกว่าให้ตัวอักษรตัวเล็กเรื่มก่อน</p><p>หากไม่ได้ใส่่ตัว key แล้ว ก็จะได้ผลลัพท์เป็น [&#39;Kumamon&#39;, &#39;My&#39;, &#39;is&#39;, &#39;name&#39;]</p><h2 id="หาข้อมูลใน-list" tabindex="-1"><a class="header-anchor" href="#หาข้อมูลใน-list" aria-hidden="true">#</a> หาข้อมูลใน List</h2><h3 id="หาว่าข้อมูลอยู่ที่ลําดับใดด้วย-index" tabindex="-1"><a class="header-anchor" href="#หาว่าข้อมูลอยู่ที่ลําดับใดด้วย-index" aria-hidden="true">#</a> หาว่าข้อมูลอยู่ที่ลำดับใดด้วย <code>.index()</code></h3><p>วิธีการใช้งาน</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>&lt;list_variable&gt;.list(&lt;key&gt;)\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>ตัวอย่างการใช้งาน</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;Happy&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;Funny&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;Fat&quot;</span><span class="token punctuation">]</span>\nindex_number <span class="token operator">=</span> my_list<span class="token punctuation">.</span>index<span class="token punctuation">(</span><span class="token string">&quot;Happy&quot;</span><span class="token punctuation">)</span>\n\n<span class="token keyword">print</span><span class="token punctuation">(</span>index_number<span class="token punctuation">)</span> <span class="token comment"># ก็จะแสดงค่าออกมาเป็น 0 เพราะคำว่า &quot;Happy&quot; อยู่ที่ลำดับที่ 0</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h1 id="ลบข้อมูลใน-list" tabindex="-1"><a class="header-anchor" href="#ลบข้อมูลใน-list" aria-hidden="true">#</a> ลบข้อมูลใน List</h1><h3 id="นําข้อมูลออกไปและไปแทนในตัวแปรด้วย-pop" tabindex="-1"><a class="header-anchor" href="#นําข้อมูลออกไปและไปแทนในตัวแปรด้วย-pop" aria-hidden="true">#</a> นำข้อมูลออกไปและไปแทนในตัวแปรด้วย <code>.pop()</code></h3><p>.pop() หากถูกเรียกใช้แล้ว ก็จะคืนค่าเข้าไปอยู่ใตัวแปรที่เรียก และทำการลบข้อมูลนั้นออกจาก List เลย<br> ให้คิดว่ามันคือการย้ายข้อมูลเข้าไปในตัวแปรนั่นเอง</p><p>วิธีการใช้งาน</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>&lt;variable name&gt;.pop(&quot;&lt;character/text/array number you want to use&gt;&quot;)\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>ตัวอย่างการใช้งาน</p><div class="language-Python ext-Python line-numbers-mode"><pre class="language-Python"><code>my_list = [&quot;Happy&quot;, &quot;Funny&quot;, &quot;Fat&quot;]\nprint(my_list.pop(1))\n\n# ปรี้นท์ตัวแปร my_list ออกมาก็จะได้ค่าเป็น &quot;Funny&quot;\n# และตัวแปร my_list ก็จะมีค่าเท่ากับ [&quot;Happy&quot;, &quot;Fat&quot;]\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="นําข้อมูลออกจาก-list-ด้วย-remove" tabindex="-1"><a class="header-anchor" href="#นําข้อมูลออกจาก-list-ด้วย-remove" aria-hidden="true">#</a> นำข้อมูลออกจาก List ด้วย <code>.remove()</code></h3><p>.remove() จะทำการลบข้อมูลที่น้องเลือกออกจากตั list เลย</p><p>!&gt; และหลังจากการทำ <code>.remove()</code> ตัว List จะทำการคำนวณลำดับใน list ใหม่</p><p>ตัวอย่างการใช้งาน</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>&lt;variable name&gt;.remove(&quot;&lt;character/text/array number you want to remove&gt;&quot;)\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>และตัวแปรก็จะออกมา โดยข้อมูลที่ถูกลบก็จะหายไปแล้ว</p><p>วิธีการใช้งาน</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;Happy&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;Funny&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;Fat&quot;</span><span class="token punctuation">]</span>\nmy_list<span class="token punctuation">.</span>remove<span class="token punctuation">(</span><span class="token string">&quot;Funny&quot;</span><span class="token punctuation">)</span>\n\n<span class="token comment"># my_list ตอนนี้มีค่าเท่ากับ [&quot;Happy&quot;, &quot;Fat&quot;]</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="แทนค่าใน-list-ด้วย-replace" tabindex="-1"><a class="header-anchor" href="#แทนค่าใน-list-ด้วย-replace" aria-hidden="true">#</a> แทนค่าใน List ด้วย <code>.replace()</code></h3><p>วิธีการใช้งาน</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>&lt;variable name&gt;.replace(&lt;text that you like to change&gt;,&lt;text that you like to change to&gt;)\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>ตัวอย่างการใช้งาน</p><div class="language-Python ext-Python line-numbers-mode"><pre class="language-Python"><code>text = &quot;Hello, my name is Kumamon&quot;\nreturn text.replace(&quot;Kumamon&quot;, &quot;Rillakuma&quot;)\n# Returns &quot;Hello, my name is Rillakuma&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div>',100),t={render:function(n,s){return e}}}}]);